import{c as a,Q as e,j as o,m as r}from"./chunks/framework.Bhbi9jCp.js";const p=JSON.parse('{"title":"文件与音视频分发原理","description":"","frontmatter":{},"headers":[],"relativePath":"杂项/文件与音视频分发原理.md","filePath":"杂项/文件与音视频分发原理.md","lastUpdated":1781599736000}'),n={name:"杂项/文件与音视频分发原理.md"};function s(d,t,l,i,h,c){return e(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="文件与音视频分发原理" tabindex="-1">文件与音视频分发原理 <a class="header-anchor" href="#文件与音视频分发原理" aria-label="Permalink to &quot;文件与音视频分发原理&quot;">​</a></h1><blockquote><p>直播是「实时生产、实时消费」,拼的是延迟;文件 / 音视频点播是「内容已存在」,拼的是<strong>缓存命中率、带宽成本、首屏与拖拽体验</strong>。本篇覆盖:静态文件分发、点播(VOD)、大文件分发、防盗链/DRM、CDN 成本调优,以及生产项目的资产分发选型。</p><p>配套阅读:<code>杂项/CDN直播原理与低延迟协议全景.md</code>(直播侧)。</p></blockquote><hr><h2 id="一、静态文件分发-图片-js-安装包-文档" tabindex="-1">一、静态文件分发(图片 / JS / 安装包 / 文档) <a class="header-anchor" href="#一、静态文件分发-图片-js-安装包-文档" aria-label="Permalink to &quot;一、静态文件分发(图片 / JS / 安装包 / 文档)&quot;">​</a></h2><p>CDN 最原始、最擅长的活——内容是<strong>不变的文件</strong>,天然适配「缓存收敛」。</p><h3 id="核心机制-缓存命中" tabindex="-1">核心机制:缓存命中 <a class="header-anchor" href="#核心机制-缓存命中" aria-label="Permalink to &quot;核心机制:缓存命中&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户请求 -&gt; 边缘节点</span></span>
<span class="line"><span>   ├─ 命中(HIT)   -&gt; 直接返回,极快、不耗源站</span></span>
<span class="line"><span>   └─ 未命中(MISS)-&gt; 回源拉取 -&gt; 缓存到边缘 -&gt; 返回</span></span></code></pre></div><p>衡量 CDN 好坏第一指标就是<strong>命中率</strong>:越高 → 源站压力越小、用户越快、带宽成本越低。</p><h3 id="决定缓存行为的-http-头" tabindex="-1">决定缓存行为的 HTTP 头 <a class="header-anchor" href="#决定缓存行为的-http-头" aria-label="Permalink to &quot;决定缓存行为的 HTTP 头&quot;">​</a></h3><table tabindex="0"><thead><tr><th>头</th><th>作用</th></tr></thead><tbody><tr><td><code>Cache-Control: max-age=</code></td><td>缓存多久,最核心</td></tr><tr><td><code>ETag</code> / <code>Last-Modified</code></td><td>内容指纹,用于「缓存还新鲜吗」的协商(304 Not Modified)</td></tr><tr><td><code>Vary</code></td><td>按某请求头分别缓存(如按 <code>Accept-Encoding</code> 区分 gzip/br)</td></tr></tbody></table><h3 id="关键难题-缓存更新-失效" tabindex="-1">关键难题:缓存更新(失效) <a class="header-anchor" href="#关键难题-缓存更新-失效" aria-label="Permalink to &quot;关键难题:缓存更新(失效)&quot;">​</a></h3><p>文件缓存到全球节点后,改了源站怎么让全网更新?两种思路:</p><ol><li><strong>主动刷新 / 预热</strong>:发版后调 CDN 的 <code>purge</code>(刷新)让旧缓存失效,或 <code>preheat</code>(预热)提前把新文件推到边缘。</li><li><strong>改 URL(更推荐)</strong>:文件名带内容哈希,如 <code>app.3f8a2c.js</code>。内容一变 URL 就变,旧的永久缓存、新的自然 MISS 回源。前端构建产物普遍用这招——既能设超长 <code>max-age</code>,又永不担心更新。</li></ol><blockquote><p>一句话:<strong>静态文件分发 = 把命中率做高 + 把缓存更新管对。</strong></p></blockquote><hr><h2 id="二、音视频点播-vod" tabindex="-1">二、音视频点播(VOD) <a class="header-anchor" href="#二、音视频点播-vod" aria-label="Permalink to &quot;二、音视频点播(VOD)&quot;">​</a></h2><p>点播 = 内容预先存好(转码、切片),用户随时点开、可拖拽、可选清晰度。建立在静态文件分发之上,多了「媒体特有处理」。</p><p><strong>与直播的根本区别</strong>:直播流式实时产生;点播<strong>文件已存在</strong>,可充分预处理、充分缓存。</p><h3 id="_1-预处理-转码-切片" tabindex="-1">1. 预处理:转码 + 切片 <a class="header-anchor" href="#_1-预处理-转码-切片" aria-label="Permalink to &quot;1. 预处理:转码 + 切片&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始 mp4 ──转码──&gt; 1080p / 720p / 480p ──切片──&gt; 一堆 .ts/.m4s 文件 + .m3u8 索引</span></span></code></pre></div><p>和直播 HLS 产物一样,但点播是<strong>离线提前切好全部切片</strong>(直播是边播边切)。</p><h3 id="_2-分发协议-与直播拉流段高度重合" tabindex="-1">2. 分发协议(与直播拉流段高度重合) <a class="header-anchor" href="#_2-分发协议-与直播拉流段高度重合" aria-label="Permalink to &quot;2. 分发协议(与直播拉流段高度重合)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>协议</th><th>点播特点</th></tr></thead><tbody><tr><td><strong>HLS / DASH</strong></td><td>主流。切片是文件,CDN 当普通静态文件缓存,完美适配;支持 ABR 多清晰度、随意拖拽</td></tr><tr><td><strong>MP4(渐进式 / Range)</strong></td><td>短视频、小文件常用;靠 HTTP Range 请求实现拖拽和边下边播</td></tr></tbody></table><h3 id="_3-点播特有关键点" tabindex="-1">3. 点播特有关键点 <a class="header-anchor" href="#_3-点播特有关键点" aria-label="Permalink to &quot;3. 点播特有关键点&quot;">​</a></h3><ul><li><strong>HTTP Range 请求(拖拽核心)</strong>:拖进度条时播放器发 <code>Range: bytes=5000000-</code>,服务器返回 <code>206 Partial Content</code>;CDN 可对大文件<strong>分片缓存</strong>,不必整文件命中才能服务。</li><li><strong>首屏秒开</strong>:把 <code>moov</code>(索引)放文件头部(<code>faststart</code>),否则要下到文件尾才能开播;热门内容前几个切片预热。</li><li><strong>ABR 自适应</strong>:按网速在多档清晰度切换;点播可比直播更激进地预缓冲(内容已存在)。</li><li><strong>防盗链 / 鉴权</strong>:见第四节。</li></ul><hr><h2 id="三、大文件分发-安装包-游戏更新-镜像" tabindex="-1">三、大文件分发(安装包 / 游戏更新 / 镜像) <a class="header-anchor" href="#三、大文件分发-安装包-游戏更新-镜像" aria-label="Permalink to &quot;三、大文件分发(安装包 / 游戏更新 / 镜像)&quot;">​</a></h2><p>大文件(几百 MB ~ 几十 GB):单文件就能打满带宽、命中率波动大、网络一断前功尽弃。四个核心技术。</p><h3 id="_1-分片-chunking" tabindex="-1">1. 分片(Chunking) <a class="header-anchor" href="#_1-分片-chunking" aria-label="Permalink to &quot;1. 分片(Chunking)&quot;">​</a></h3><p>把大文件切成固定块(如 4MB),分发/缓存/校验都以块为单位。</p><ul><li><strong>CDN 分片缓存</strong>:不必整文件命中,这块 HIT、那块 MISS 分别处理。</li><li><strong>并行下载</strong>:客户端多连接同时拉不同块,打满带宽。</li><li><strong>按块校验</strong>:每块带哈希,坏了只重传那一块。</li></ul><h3 id="_2-断点续传-range-请求" tabindex="-1">2. 断点续传(Range 请求) <a class="header-anchor" href="#_2-断点续传-range-请求" aria-label="Permalink to &quot;2. 断点续传(Range 请求)&quot;">​</a></h3><p>和点播拖拽同一套 <code>Range: bytes=</code> 机制:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>下载到 60% 断网 -&gt; 记录已下字节 -&gt; 重连 Range: bytes=60000000- -&gt; 接着下</span></span></code></pre></div><h3 id="_3-增量更新-差量-delta" tabindex="-1">3. 增量更新(差量 / Delta) <a class="header-anchor" href="#_3-增量更新-差量-delta" aria-label="Permalink to &quot;3. 增量更新(差量 / Delta)&quot;">​</a></h3><p>游戏/APP 更新关键省流手段:只下「变了的部分」。</p><ul><li><strong>二进制 diff(bsdiff 等)</strong>:老版本 + 补丁 = 新版本,补丁常只有整包几十分之一。</li><li><strong>块级去重</strong>:新老版本按块比对,只下不同块(rsync 思路)。</li><li>代价:服务端为「每对版本」生成补丁或维护块索引,<strong>计算/存储换带宽</strong>。</li></ul><h3 id="_4-p2p-cdn-削峰杀手锏" tabindex="-1">4. P2P-CDN(削峰杀手锏) <a class="header-anchor" href="#_4-p2p-cdn-削峰杀手锏" aria-label="Permalink to &quot;4. P2P-CDN(削峰杀手锏)&quot;">​</a></h3><p>大型更新(海量用户同时下)纯靠 CDN 带宽成本爆炸,让用户互传:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CDN 提供「种子 + 调度」,用户A下好的块直接传给用户B</span></span>
<span class="line"><span>   -&gt; CDN 只承担一部分,大头由用户上行带宽分摊</span></span></code></pre></div><ul><li>典型:游戏更新、大型直播削峰。</li><li>代价:NAT 穿透、调度复杂、上行参差、隐私顾虑。通常 <strong>CDN 兜底 + P2P 削峰</strong>混合。</li></ul><blockquote><p><strong>大文件心法</strong>:分片是地基,Range 管断点,Delta 省更新流量,P2P 削峰值带宽。</p></blockquote><hr><h2 id="四、防盗链-drm-分层递进" tabindex="-1">四、防盗链 / DRM(分层递进) <a class="header-anchor" href="#四、防盗链-drm-分层递进" aria-label="Permalink to &quot;四、防盗链 / DRM(分层递进)&quot;">​</a></h2><p>内容是有价值的存量资产,要防三件事:<strong>盗用带宽、盗看内容、盗录内容</strong>。越往后越强也越贵。</p><h3 id="第-0-层-referer-防盗链-最弱-挡君子" tabindex="-1">第 0 层:Referer 防盗链(最弱,挡君子) <a class="header-anchor" href="#第-0-层-referer-防盗链-最弱-挡君子" aria-label="Permalink to &quot;第 0 层:Referer 防盗链(最弱,挡君子)&quot;">​</a></h3><p>CDN 校验 <code>Referer</code> 是否在白名单域名。零成本,但 Referer 可伪造/可为空,只挡「别的网站直接盗链」。</p><h3 id="第-1-层-url-签名鉴权-主力-必上" tabindex="-1">第 1 层:URL 签名鉴权(主力,必上) <a class="header-anchor" href="#第-1-层-url-签名鉴权-主力-必上" aria-label="Permalink to &quot;第 1 层:URL 签名鉴权(主力,必上)&quot;">​</a></h3><p>给资源 URL 加时效签名,点播标配:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://cdn.example.com/video/123.m3u8?t=1718500000&amp;sign=a3f9c2...</span></span>
<span class="line"><span>                                        ↑过期时间      ↑ HMAC(path+t+密钥)</span></span></code></pre></div><ul><li>边缘节点用密钥重算签名,对不上或 <code>t</code> 过期 → 拒绝。</li><li>密钥只在后端和 CDN 之间,客户端拿不到,无法自造合法 URL。</li><li>进阶:绑定用户 IP、限制 UA。</li><li><strong>HLS 细节</strong>:m3u8 引用的每个 <code>.ts</code> 切片 URL 也要各自带签名(或统一鉴权回源),通常对<strong>整个路径前缀签名</strong>。</li></ul><h3 id="第-2-层-鉴权回源-token-动态校验" tabindex="-1">第 2 层:鉴权回源 / Token(动态校验) <a class="header-anchor" href="#第-2-层-鉴权回源-token-动态校验" aria-label="Permalink to &quot;第 2 层:鉴权回源 / Token(动态校验)&quot;">​</a></h3><p>边缘收到请求时回调业务后端问「该用户有无权限」,后端查订单/会员后放行。</p><ul><li>比静态签名灵活:能实时吊销、按权限动态控制。</li><li>代价:多一次回源鉴权,有延迟和后端压力,通常缓存鉴权结果。</li></ul><h3 id="第-3-层-drm-版权加密-付费内容终极防线" tabindex="-1">第 3 层:DRM(版权加密,付费内容终极防线) <a class="header-anchor" href="#第-3-层-drm-版权加密-付费内容终极防线" aria-label="Permalink to &quot;第 3 层:DRM(版权加密,付费内容终极防线)&quot;">​</a></h3><p>前面几层只防「链接被盗」,内容本身仍是明文(抓包可得)。DRM 把<strong>内容本身加密</strong>,只有授权设备能解密:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>内容用密钥加密分发 -&gt; 播放器向 License Server 申请密钥</span></span>
<span class="line"><span>   -&gt; 校验授权 + 设备安全等级 -&gt; 下发密钥 -&gt; 在安全环境(TEE)内解密播放</span></span></code></pre></div><table tabindex="0"><thead><tr><th>DRM</th><th>平台</th></tr></thead><tbody><tr><td><strong>Widevine</strong></td><td>Android / Chrome</td></tr><tr><td><strong>FairPlay</strong></td><td>iOS / Safari</td></tr><tr><td><strong>PlayReady</strong></td><td>Windows / Edge</td></tr></tbody></table><ul><li>配合 <strong>CENC(通用加密)</strong>:一份加密内容三种 DRM 共用,不用加密三遍。</li><li>配合硬件层(HDCP / 安全输出)可禁截屏录屏。</li><li>代价:接入复杂、有授权成本、需 License 服务。<strong>只有付费版权内容才值得上。</strong></li></ul><h3 id="落地分层建议" tabindex="-1">落地分层建议 <a class="header-anchor" href="#落地分层建议" aria-label="Permalink to &quot;落地分层建议&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>普通图片/短视频      -&gt; Referer 防盗链 + URL 签名</span></span>
<span class="line"><span>有价值的自有视频内容  -&gt; URL 签名 + 鉴权回源</span></span>
<span class="line"><span>付费课程 / 版权影视   -&gt; 上述 + DRM(CENC + Widevine/FairPlay)</span></span></code></pre></div><blockquote><p>一句话:<strong>签名 URL 防蹭带宽,鉴权回源防越权白嫖,DRM 防内容本身被拿走。</strong> 按内容价值逐层加。</p></blockquote><hr><h2 id="五、cdn-命中率-带宽成本优化-实战" tabindex="-1">五、CDN 命中率 / 带宽成本优化(实战) <a class="header-anchor" href="#五、cdn-命中率-带宽成本优化-实战" aria-label="Permalink to &quot;五、CDN 命中率 / 带宽成本优化(实战)&quot;">​</a></h2><p>CDN 计费 = 流量/带宽,<strong>命中率直接决定成本</strong>:命中率从 90% 提到 95%,回源流量直接砍一半。</p><h3 id="_1-提高命中率" tabindex="-1">1. 提高命中率 <a class="header-anchor" href="#_1-提高命中率" aria-label="Permalink to &quot;1. 提高命中率&quot;">​</a></h3><ul><li><strong>缓存键(Cache Key)治理(最常见的坑)</strong>:默认缓存键含完整 URL。若 URL 带无关参数(<code>?from=wechat&amp;utm=xxx</code>),CDN 会当<strong>不同资源</strong>分别缓存 → 命中率暴跌。解法:配置 CDN <strong>忽略无关 query</strong>,只留真正影响内容的参数。</li><li><strong>合理 <code>Cache-Control</code></strong>:带哈希文件名的静态资源 → <code>max-age=31536000, immutable</code>;会变的资源 → 适中 max-age + <code>ETag</code> 协商(304 省流);别给能缓存的东西发 <code>no-cache</code>/<code>private</code>(常见误配,直接废掉 CDN)。</li><li><strong>回源合并(请求折叠)</strong>:热点突发时大量边缘同时 MISS 回源会冲垮源站 → 开 collapsed forwarding,同一资源并发回源合并成一次。</li><li><strong>预热(Preheat)</strong>:大促/新版本/热门内容上线<strong>前</strong>主动推到边缘。</li><li><strong>分层缓存</strong>:边缘 MISS 先找中心节点(L2),L2 再回源,源站只面对少量 L2 回源。</li></ul><h3 id="_2-降低带宽成本" tabindex="-1">2. 降低带宽成本 <a class="header-anchor" href="#_2-降低带宽成本" aria-label="Permalink to &quot;2. 降低带宽成本&quot;">​</a></h3><ul><li><strong>压缩</strong>:文本类 gzip/br(省 60-80%);图片用 <strong>WebP/AVIF</strong>(比 JPG 省 30-50%)。</li><li><strong>图片/视频按需处理</strong>:CDN 边缘<strong>实时裁剪/压缩/转格式</strong>,同一原图按设备场景下发不同尺寸。</li><li><strong>冷热分层 + 长尾治理</strong>:冷门大文件命中率低、是成本黑洞,单独低频存储或不放 CDN。</li><li><strong>多 CDN 调度</strong>:大流量接多家,按价格 + 质量 + 区域动态调度,压价又容灾。</li><li><strong>看懂账单</strong>:区分回源流量(贵,靠命中率压)和下行流量(走量)。</li></ul><h3 id="_3-监控指标" tabindex="-1">3. 监控指标 <a class="header-anchor" href="#_3-监控指标" aria-label="Permalink to &quot;3. 监控指标&quot;">​</a></h3><ul><li>命中率(看<strong>字节</strong>命中率,不是请求命中率)</li><li>回源率 / 回源带宽</li><li>首字节时间(TTFB)、下载速度</li><li>5xx / 回源失败率</li></ul><blockquote><p>心法:<strong>先治缓存键和 Cache-Control(命中率),再上压缩和图片处理(体积),最后多 CDN 调度(单价)。</strong> 顺序别反——命中率没治好,后面都是给漏桶补水。</p></blockquote><hr><h2 id="六、生产项目资产分发选型" tabindex="-1">六、生产项目资产分发选型 <a class="header-anchor" href="#六、生产项目资产分发选型" aria-label="Permalink to &quot;六、生产项目资产分发选型&quot;">​</a></h2><p>把上面的原理收口到一个真实生产项目的常见四类资产。</p><h3 id="_1-图片-量最大、最高频" tabindex="-1">1. 图片(量最大、最高频) <a class="header-anchor" href="#_1-图片-量最大、最高频" aria-label="Permalink to &quot;1. 图片(量最大、最高频)&quot;">​</a></h3><ul><li>协议:普通 HTTP + CDN 缓存,文件天然适配,不用改造。</li><li><strong>上「图片处理 CDN」</strong>:存一张原图,URL 带参数实时出不同尺寸/格式/质量(<code>pic.jpg?w=400&amp;format=webp</code>),列表缩略图、详情大图、不同 DPR 屏各取所需,省带宽 + 提首屏。</li><li>缓存:文件名带版本/哈希,<code>max-age</code> 拉满,改图换 URL。</li><li>缓存键:<strong>忽略 <code>utm</code> 等营销参数</strong>,只留 <code>w/h/format</code> 这类真正影响产物的参数。</li><li>格式:优先 WebP/AVIF,按 <code>Accept</code> 头自动降级 JPG。</li></ul><h3 id="_2-视频" tabindex="-1">2. 视频 <a class="header-anchor" href="#_2-视频" aria-label="Permalink to &quot;2. 视频&quot;">​</a></h3><ul><li><strong>点播 HLS/DASH</strong>:转码多档码率 + 切片,ABR 自适应,文件型 CDN 直接分发。</li><li>防护按价值分层:免费/营销视频 → URL 签名;<strong>付费内容</strong> → URL 签名 + 鉴权回源(校验是否已购);版权敏感、防盗录要求高再评估 DRM(先用签名+鉴权回源跑起来,有盗版实锤再上 DRM)。</li><li>首屏:<code>faststart</code>(moov 前置)+ 热门切片预热。</li></ul><h3 id="_3-安装包-热更新包" tabindex="-1">3. 安装包 / 热更新包 <a class="header-anchor" href="#_3-安装包-热更新包" aria-label="Permalink to &quot;3. 安装包 / 热更新包&quot;">​</a></h3><ul><li>安装包:大文件那套——分片 + Range 断点续传,CDN 分片缓存。</li><li><strong>优先增量(Delta)更新</strong>,只下变化部分。</li><li>新版本发布<strong>预热</strong>到边缘,避免发版瞬间海量回源打爆源站。</li><li>量级真的很大再考虑 P2P-CDN,初期不必。</li></ul><h3 id="_4-前端静态资源-js-css" tabindex="-1">4. 前端静态资源(JS/CSS) <a class="header-anchor" href="#_4-前端静态资源-js-css" aria-label="Permalink to &quot;4. 前端静态资源(JS/CSS)&quot;">​</a></h3><ul><li>构建产物<strong>文件名带内容哈希</strong>,<code>max-age</code> 拉满 + <code>immutable</code>。</li><li>HTML 入口 <code>no-cache</code> 或短 max-age(它引用带哈希的资源,保证更新即时生效)。</li></ul><h3 id="选型小结" tabindex="-1">选型小结 <a class="header-anchor" href="#选型小结" aria-label="Permalink to &quot;选型小结&quot;">​</a></h3><table tabindex="0"><thead><tr><th>资产</th><th>协议/方式</th><th>缓存策略</th><th>防护</th><th>重点</th></tr></thead><tbody><tr><td>图片</td><td>HTTP + 图片处理 CDN</td><td>哈希URL + 长max-age</td><td>Referer 防盗链</td><td>实时压缩/转格式、缓存键治理</td></tr><tr><td>视频</td><td>点播 HLS + ABR</td><td>切片长缓存</td><td>签名URL + 鉴权回源(付费),DRM 待定</td><td>防白嫖、首屏秒开</td></tr><tr><td>安装包/更新</td><td>大文件 分片+Range</td><td>长缓存 + 预热</td><td>签名URL</td><td>增量更新省流</td></tr><tr><td>前端 JS/CSS</td><td>HTTP</td><td>哈希URL immutable</td><td>—</td><td>入口短缓存,资源永久缓存</td></tr></tbody></table><blockquote><p><strong>优先级</strong>:① 先做图片的「图片处理 CDN + 缓存键治理」(收益最大、最快见效);② 视频用「HLS + 签名URL + 鉴权回源」起步,DRM 留后手;③ 前端用哈希文件名标准方案;④ 安装包做增量更新。<strong>别一上来就上 DRM、P2P 这些重武器,按内容价值和规模渐进加。</strong></p></blockquote><hr><h2 id="七、与直播对照-把整个体系连起来" tabindex="-1">七、与直播对照(把整个体系连起来) <a class="header-anchor" href="#七、与直播对照-把整个体系连起来" aria-label="Permalink to &quot;七、与直播对照(把整个体系连起来)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>直播</th><th>点播 / 文件</th></tr></thead><tbody><tr><td>内容产生</td><td>实时流式</td><td>预先存好的文件</td></tr><tr><td>核心诉求</td><td><strong>低延迟</strong></td><td><strong>高命中率 + 低成本 + 拖拽体验</strong></td></tr><tr><td>切片</td><td>边播边切</td><td>离线提前全部切好</td></tr><tr><td>缓存</td><td>切片生命周期极短(秒级)</td><td>长期缓存,命中率可做到很高</td></tr><tr><td>协议</td><td>RTMP/SRT 推 + HLS/FLV/WebRTC 拉</td><td>HLS/DASH/MP4(纯拉)</td></tr><tr><td>CDN 改造</td><td>WebRTC 等流型要重改造</td><td>几乎不用改,文件天然适配</td></tr><tr><td>关键指标</td><td>延迟、卡顿率</td><td>命中率、首屏、带宽成本</td></tr><tr><td>鉴权</td><td>推流鉴权为主</td><td>URL 签名 / DRM 等内容保护更重</td></tr></tbody></table><blockquote><p><strong>总结</strong>:直播是「时间换不回来,所以拼延迟」;点播/文件是「内容不会变,所以拼缓存、拼成本、拼内容保护」。<strong>HLS 切片这套技术两边通用</strong>——很多平台直播结束后能无缝转点播回看,就是因为切片文件留下来即点播。</p></blockquote>`,90)])])}const u=a(n,[["render",s]]);export{p as __pageData,u as default};
